#include <vector>
#include <string>
#include <algorithm>
#include <functional>

using namespace std;

long long solve(long long n, vector<vector<long long>> edges, string label) {
    vector<vector<long long>> adj(n);
    for (auto& e : edges) {
        adj[e[0]].push_back(e[1]);
        adj[e[1]].push_back(e[0]);
    }
    long long max_len = 1;

    auto is_palindrome = [](string s) {
        int left = 0, right = s.length() - 1;
        while (left < right) {
            if (s[left] != s[right]) return false;
            left++;
            right--;
        }
        return true;
    };

    function<void(long long, long long, string)> dfs = [&](long long current, long long visited, string path) {
        if (is_palindrome(path)) {
            max_len = max(max_len, (long long)path.length());
        }
        for (auto neighbor : adj[current]) {
            if (visited & (1 << neighbor)) continue;
            string new_path = path + label[neighbor];
            dfs(neighbor, visited | (1 << neighbor), new_path);
        }
    };

    for (long long start = 0; start < n; ++start) {
        string initial_path = string(1, label[start]);
        dfs(start, 1 << start, initial_path);
    }

    return max_len;
}
