#include <vector>
#include <string>
#include <algorithm>

using namespace std;

long long solve(long long n, vector<vector<long long>> edges, string label) {
    vector<vector<long long>> adj(n);
    for (auto& e : edges) {
        long long u = e[0], v = e[1];
        adj[u].push_back(v);
        adj[v].push_back(u);
    }
    long long max_len = 0;

    auto dfs = [&](long long current, long long visited_mask, vector<long long>& path) -> void {
        long long k = path.size();
        bool is_pal = true;
        for (long long i = 0; i < k / 2; ++i) {
            if (label[path[i]] != label[path[k - 1 - i]]) {
                is_pal = false;
                break;
            }
        }
        if (is_pal) {
            max_len = max(max_len, k);
        }

        for (auto neighbor : adj[current]) {
            if (visited_mask & (1 << neighbor)) continue;
            path.push_back(neighbor);
            long long new_visited = visited_mask | (1 << neighbor);
            dfs(neighbor, new_visited, path);
            path.pop_back();
        }
    };

    for (long long start = 0; start < n; ++start) {
        vector<long long> path;
        path.push_back(start);
        long long visited_mask = 1 << start;
        dfs(start, visited_mask, path);
    }

    return max_len;
}
